if (!defined('ABSPATH')) exit;

class UUF_User_Files_Upload {
	const NONCE_ACTION = 'uuf_upload_files_action';
	const NONCE_NAME   = 'uuf_nonce';

	public function __construct() {
		add_action('init', [$this, 'handle_upload']);
		add_shortcode('user_files_upload', [$this, 'shortcode']);
		add_action('admin_post_uuf_upload', [$this, 'handle_upload']);
		add_action('admin_post_nopriv_uuf_upload', [$this, 'handle_upload']);
	}

	public function shortcode($atts = []) {
		if (!is_user_logged_in()) {
			return '<p>You must be logged in to upload files.</p>';
		}

		$atts = shortcode_atts([
			'redirect' => '',
			'max_mb'   => '20',
		], $atts, 'user_files_upload');

		$redirect = $atts['redirect'] ? esc_url($atts['redirect']) : esc_url($this->current_url());
		$max_mb = floatval($atts['max_mb']);
		if ($max_mb <= 0) $max_mb = 20;

		$msg = '';
		if (isset($_GET['uuf_msg'])) {
			$msg = sanitize_text_field(wp_unslash($_GET['uuf_msg']));
		}

		$max_bytes = (int) round($max_mb * 1024 * 1024);

		$out  = '';
		if ($msg) {
			$out .= '<div class="uuf-message" style="padding:10px;border:1px solid #ddd;margin:10px 0;">' . esc_html($msg) . '</div>';
		}

		$out .= '<form method="post" enctype="multipart/form-data" action="' . esc_url(admin_url('admin-post.php')) . '">';
		$out .= '<input type="hidden" name="action" value="uuf_upload" />';
		$out .= wp_nonce_field(self::NONCE_ACTION, self::NONCE_NAME, true, false);
		$out .= '<input type="hidden" name="uuf_redirect" value="' . esc_attr($redirect) . '" />';
		$out .= '<input type="hidden" name="uuf_max_bytes" value="' . esc_attr($max_bytes) . '" />';

		$out .= '<p><label><strong>Profile Picture (optional)</strong><br />';
		$out .= '<input type="file" name="uuf_profile_picture" accept="image/*" /></label></p>';

		$out .= '<p><label><strong>Document(s) (optional)</strong><br />';
		$out .= '<input type="file" name="uuf_documents[]" multiple /></label></p>';

		$out .= '<p><button type="submit">Upload</button></p>';
		$out .= '</form>';

		$out .= $this->render_user_files_list(get_current_user_id());

		return $out;
	}

	private function render_user_files_list($user_id) {
		$files = get_user_meta($user_id, '_uuf_files', true);
		if (!is_array($files) || empty($files)) return '';

		$out = '<div class="uuf-files"><h3>Your Uploaded Files</h3><ul>';
		foreach (array_reverse($files) as $f) {
			$url  = isset($f['url']) ? esc_url($f['url']) : '';
			$name = isset($f['original_name']) ? esc_html($f['original_name']) : 'File';
			$type = isset($f['type']) ? esc_html($f['type']) : '';
			$when = isset($f['time']) ? esc_html(date_i18n(get_option('date_format') . ' ' . get_option('time_format'), intval($f['time']))) : '';
			$out .= '<li>';
			if ($url) $out .= '<a href="' . $url . '" target="_blank" rel="noopener noreferrer">' . $name . '</a>';
			else $out .= $name;
			if ($type) $out .= ' <small>(' . $type . ')</small>';
			if ($when) $out .= ' <small>- ' . $when . '</small>';
			$out .= '</li>';
		}
		$out .= '</ul></div>';

		return $out;
	}

	public function handle_upload() {
		if (!isset($_POST['action']) || $_POST['action'] !== 'uuf_upload') return;

		$redirect = isset($_POST['uuf_redirect']) ? esc_url_raw(wp_unslash($_POST['uuf_redirect'])) : $this->current_url();
		if (!$redirect) $redirect = home_url('/');

		if (!is_user_logged_in()) {
			$this->safe_redirect_with_msg($redirect, 'You must be logged in to upload files.');
		}

		if (!isset($_POST[self::NONCE_NAME]) || !wp_verify_nonce(sanitize_text_field(wp_unslash($_POST[self::NONCE_NAME])), self::NONCE_ACTION)) {
			$this->safe_redirect_with_msg($redirect, 'Security check failed.');
		}

		$user_id = get_current_user_id();

		$max_bytes = isset($_POST['uuf_max_bytes']) ? intval($_POST['uuf_max_bytes']) : 20 * 1024 * 1024;
		if ($max_bytes <= 0) $max_bytes = 20 * 1024 * 1024;

		$results = [];
		$errors = [];

		$base = $this->get_user_files_base_dir();
		if (!$base) {
			$this->safe_redirect_with_msg($redirect, 'Could not initialize upload directory.');
		}

		$user_dir = trailingslashit($base['dir']) . 'user-' . $user_id;
		$user_url = trailingslashit($base['url']) . 'user-' . $user_id;

		if (!wp_mkdir_p($user_dir)) {
			$this->safe_redirect_with_msg($redirect, 'Could not create user upload directory.');
		}

		$allowed_mimes = $this->allowed_mimes();

		if (isset($_FILES['uuf_profile_picture'])) {
			$r = $this->process_single_file($_FILES['uuf_profile_picture'], $user_dir, $user_url, $allowed_mimes, $max_bytes, 'profile_picture');
			if ($r['ok']) {
				update_user_meta($user_id, '_uuf_profile_picture_url', $r['file']['url']);
				$this->append_user_file_meta($user_id, $r['file']);
				$results[] = 'Profile picture uploaded.';
			} elseif ($r['skipped']) {
				// no file
			} else {
				$errors[] = 'Profile picture: ' . $r['error'];
			}
		}

		if (isset($_FILES['uuf_documents'])) {
			$docs = $this->normalize_files_array($_FILES['uuf_documents']);
			foreach ($docs as $doc) {
				$r = $this->process_single_file($doc, $user_dir, $user_url, $allowed_mimes, $max_bytes, 'document');
				if ($r['ok']) {
					$this->append_user_file_meta($user_id, $r['file']);
					$results[] = 'Document uploaded: ' . $r['file']['original_name'];
				} elseif ($r['skipped']) {
					// ignore empty
				} else {
					$errors[] = ($doc['name'] ? $doc['name'] : 'Document') . ': ' . $r['error'];
				}
			}
		}

		if (!$results && !$errors) {
			$this->safe_redirect_with_msg($redirect, 'No files selected.');
		}

		$msg = '';
		if ($results) $msg .= implode(' ', $results) . ' ';
		if ($errors) $msg .= 'Errors: ' . implode(' | ', $errors);

		$this->safe_redirect_with_msg($redirect, trim($msg));
	}

	private function allowed_mimes() {
		return [
			// Images
			'jpg|jpeg|jpe' => 'image/jpeg',
			'png'          => 'image/png',
			'gif'          => 'image/gif',
			'webp'         => 'image/webp',
			'heic'         => 'image/heic',
			'heif'         => 'image/heif',

			// PDF
			'pdf'          => 'application/pdf',

			// MS Office & OpenXML
			'doc'          => 'application/msword',
			'docx'         => 'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
			'xls'          => 'application/vnd.ms-excel',
			'xlsx'         => 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
			'ppt'          => 'application/vnd.ms-powerpoint',
			'pptx'         => 'application/vnd.openxmlformats-officedocument.presentationml.presentation',

			// OpenDocument
			'odt'          => 'application/vnd.oasis.opendocument.text',
			'ods'          => 'application/vnd.oasis.opendocument.spreadsheet',
			'odp'          => 'application/vnd.oasis.opendocument.presentation',

			// Text
			'txt'          => 'text/plain',
			'csv'          => 'text/csv',
			'rtf'          => 'application/rtf',

			// Archives (optional; remove if not desired)
			'zip'          => 'application/zip',
		];
	}

	private function get_user_files_base_dir() {
		$uploads = wp_upload_dir(null, false);
		if (empty($uploads['basedir']) || empty($uploads['baseurl'])) return false;

		$dir = trailingslashit($uploads['basedir']) . 'user-files';
		$url = trailingslashit($uploads['baseurl']) . 'user-files';

		if (!wp_mkdir_p($dir)) return false;

		$this->ensure_protection_files($dir);

		return ['dir' => $dir, 'url' => $url];
	}

	private function ensure_protection_files($dir) {
		$index = trailingslashit($dir) . 'index.html';
		if (!file_exists($index)) {
			@file_put_contents($index, '');
		}

		$htaccess = trailingslashit($dir) . '.htaccess';
		if (!file_exists($htaccess)) {
			$rules = "Options -Indexes\n<FilesMatch \"\\.(php|phtml|php3|php4|php5|php7|php8|phar)$\">\nDeny from all\n</FilesMatch>\n";
			@file_put_contents($htaccess, $rules);
		}
	}

	private function normalize_files_array($files) {
		$normalized = [];
		if (!is_array($files) || !isset($files['name'])) return $normalized;

		if (!is_array($files['name'])) {
			$normalized[] = $files;
			return $normalized;
		}

		$count = count($files['name']);
		for ($i = 0; $i < $count; $i++) {
			$normalized[] = [
				'name'     => $files['name'][$i] ?? '',
				'type'     => $files['type'][$i] ?? '',
				'tmp_name' => $files['tmp_name'][$i] ?? '',
				'error'    => $files['error'][$i] ?? UPLOAD_ERR_NO_FILE,
				'size'     => $files['size'][$i] ?? 0,
			];
		}
		return $normalized;
	}

	private function process_single_file($file, $dest_dir, $dest_url, $allowed_mimes, $max_bytes, $kind) {
		$out = ['ok' => false, 'skipped' => false, 'error' => '', 'file' => null];

		if (!isset($file['error']) || $file['error'] === UPLOAD_ERR_NO_FILE) {
			$out['skipped'] = true;
			return $out;
		}

		if (!empty($file['error']) && $file['error'] !== UPLOAD_ERR_OK) {
			$out['error'] = $this->upload_err_msg($file['error']);
			return $out;
		}

		if (empty($file['tmp_name']) || !is_uploaded_file($file['tmp_name'])) {
			$out['error'] = 'Invalid upload.';
			return $out;
		}

		$size = isset($file['size']) ? intval($file['size']) : 0;
		if ($size <= 0) {
			$out['error'] = 'Empty file.';
			return $out;
		}
		if ($size > $max_bytes) {
			$out['error'] = 'File exceeds size limit.';
			return $out;
		}

		$original_name = isset($file['name']) ? sanitize_file_name(wp_unslash($file['name'])) : 'upload';
		if (!$original_name) $original_name = 'upload';

		$wp_filetype = wp_check_filetype_and_ext($file['tmp_name'], $original_name, $allowed_mimes);
		$ext = isset($wp_filetype['ext']) ? $wp_filetype['ext'] : '';
		$type = isset($wp_filetype['type']) ? $wp_filetype['type'] : '';

		if (!$ext || !$type) {
			$out['error'] = 'File type not allowed.';
			return $out;
		}

		$subdir = ($kind === 'profile_picture') ? 'profile-pictures' : 'documents';
		$target_dir = trailingslashit($dest_dir) . $subdir;
		$target_url = trailingslashit($dest_url) . $subdir;

		if (!wp_mkdir_p($target_dir)) {
			$out['error'] = 'Could not create destination directory.';
			return $out;
		}

		$this->ensure_protection_files($target_dir);

		$base = pathinfo($original_name, PATHINFO_FILENAME);
		$base = sanitize_title_with_dashes($base);
		if (!$base) $base = 'file';

		$time = time();
		$rand = wp_generate_password(8, false, false);
		$final_name = $base . '-' . $time . '-' . $rand . '.' . $ext;

		$dest_path = trailingslashit($target_dir) . $final_name;

		if (!@move_uploaded_file($file['tmp_name'], $dest_path)) {
			$out['error'] = 'Failed to move uploaded file.';
			return $out;
		}

		@chmod($dest_path, 0644);

		$file_entry = [
			'kind'          => $kind,
			'original_name' => $original_name,
			'file_name'     => $final_name,
			'path'          => $dest_path,
			'url'           => trailingslashit($target_url) . rawurlencode($final_name),
			'type'          => $type,
			'ext'           => $ext,
			'size'          => $size,
			'time'          => $time,
		];

		$out['ok'] = true;
		$out['file'] = $file_entry;

		return $out;
	}

	private function append_user_file_meta($user_id, $file_entry) {
		$files = get_user_meta($user_id, '_uuf_files', true);
		if (!is_array($files)) $files = [];
		$files[] = $file_entry;
		if (count($files) > 200) {
			$files = array_slice($files, -200);
		}
		update_user_meta($user_id, '_uuf_files', $files);
	}

	private function upload_err_msg($code) {
		switch ((int)$code) {
			case UPLOAD_ERR_INI_SIZE: return 'File exceeds server limit.';
			case UPLOAD_ERR_FORM_SIZE: return 'File exceeds form limit.';
			case UPLOAD_ERR_PARTIAL: return 'File was only partially uploaded.';
			case UPLOAD_ERR_NO_TMP_DIR: return 'Missing a temporary folder.';
			case UPLOAD_ERR_CANT_WRITE: return 'Failed to write file to disk.';
			case UPLOAD_ERR_EXTENSION: return 'Upload stopped by a PHP extension.';
			default: return 'Upload error.';
		}
	}

	private function safe_redirect_with_msg($redirect, $msg) {
		$url = $this->add_query_arg_safe($redirect, [
			'uuf_msg' => $msg,
		]);
		wp_safe_redirect($url);
		exit;
	}

	private function add_query_arg_safe($url, $args) {
		$frag = '';
		$hash_pos = strpos($url, '#');
		if ($hash_pos !== false) {
			$frag = substr($url, $hash_pos);
			$url  = substr($url, 0, $hash_pos);
		}
		$url = add_query_arg($args, $url);
		return $url . $frag;
	}

	private function current_url() {
		$scheme = is_ssl() ? 'https' : 'http';
		$host = isset($_SERVER['HTTP_HOST']) ? sanitize_text_field(wp_unslash($_SERVER['HTTP_HOST'])) : '';
		$uri  = isset($_SERVER['REQUEST_URI']) ? wp_unslash($_SERVER['REQUEST_URI']) : '';
		$uri  = is_string($uri) ? $uri : '';
		$uri  = preg_replace('/[\r\n]/', '', $uri);
		if (!$host) return home_url('/');
		return esc_url_raw($scheme . '://' . $host . $uri);
	}
}

new UUF_User_Files_Upload();